// 1. 抓取剛剛建好的「主訂單 ID」
const recordId = $input.first().json.id;

// 2. 獲取打包好的子項目清單
const subItems = $('Calculate Profit & Pack Items').first().json.Sub_Items || [];

// 3. 轉換為 n8n 資料格式
return subItems.map(item => ({
  json: {
    Product_ID: item.Product_Record_ID,
    Quantity: item.Quantity,
    Notes: item.Notes,
    Main_Order_ID: recordId,
    Order_Item_Key: item.Order_Item_Key
  }
}));

// API V40.5 協議：批量收集 SKU (安全重生版)
const items = $input.all();

// 強制數組檢查與防禦
if (!Array.isArray(items) || items.length === 0) {
    return { json: { batchFormula: "RECORD_ID()='INVALID'", hasItems: false } };
}

const skus = [...new Set(items.map(i => i.json.Search_SKU).filter(s => s && s !== "無商品"))];

if (skus.length === 0) {
    return { json: { batchFormula: "RECORD_ID()='INVALID'", hasItems: false } };
}

const formulaParts = skus.map(s => `{Product_Name} = '${s}'`);
const finalFormula = skus.length > 1 ? `OR(${formulaParts.join(',')})` : formulaParts[0];

return { json: { batchFormula: finalFormula, hasItems: true } };

// API V40.5 協議：本地數據映射 Mapping (存活定律版)
const costNode = $("Fetch Exact Base Cost");
const originalItemsNode = $("Parse Items & Generate SKU");

// 確保節點存在且有資料，否則安全回退
const costResults = costNode ? costNode.all() : [];
const originalItems = originalItemsNode ? originalItemsNode.all() : [];

const costMap = {};
costResults.forEach(r => {
    if (r.json && r.json.id) {
        costMap[r.json.Product_Name] = {
            id: r.json.id,
            Product_Name: r.json.Product_Name,
            Total_Base_Cost: Number(r.json.Total_Base_Cost) || 0
        };
    }
});

return originalItems.map(item => {
    const sku = item.json.Search_SKU;
    // 實裝 Section 14.5 數據映射存活定律：找不到成本則預設為 0
    const costData = costMap[sku] || { id: null, Product_Name: sku, Total_Base_Cost: 0 };
    return {
        json: {
            ...item.json,
            ...costData
        }
    };
});

// === Freehandsss V40.5 (安全重生版): 大腦 2 號 (利潤精算 - 並將子項目打包) ===

const parseNode = $('Parse Items & Generate SKU');
const parseNodeItems = parseNode ? parseNode.all() : [];

if (parseNodeItems.length === 0) {
    // 根本性防禦：如果連初始解析都沒有，傳回基本的空 payload 避免當機
    return [{ json: { Total_Revenue: 0, Total_Cost: 0, Final_Profit: 0, Sub_Items: [] } }];
}

const firstNodeData = parseNodeItems[0].json || {};
const totalRevenue = Number(firstNodeData.Total_Revenue) || 0;
const rawFormState = firstNodeData.Raw_Form_State || "";

let deposit = 0;
let balance = 0;
let additionalFee = 0;

try {
    const triggerNode = $('Receive Dashboard Order');
    const triggerBody = (triggerNode && triggerNode.first()) ? (triggerNode.first().json.body || triggerNode.first().json) : {};
    deposit = Number(triggerBody.Deposit) || 0;
    balance = Number(triggerBody.Balance) || 0;
    additionalFee = Number(triggerBody.Additional_Fee) || 0;
} catch (error) { }

let totalBaseCost = 0;
let packedItems = [];

const items = $input.all(); 
for (let i = 0; i < parseNodeItems.length; i++) {
    // 終極防禦機制：當 $input 找不到對應 item 時安全回退，避免 Cannot read properties of undefined
    let originalItemData = parseNodeItems[i].json || {};
    let itemData = (items[i] && items[i].json) ? items[i].json : originalItemData;

    let itemCost = Number(itemData.Total_Base_Cost) || 0;
    totalBaseCost += itemCost;

    packedItems.push({
        Product_Record_ID: itemData.id || null, 
        Product_Name: itemData.Product_Name || originalItemData.Search_SKU || "Unknown SKU",
        Total_Base_Cost: itemCost,
        Quantity: Number(originalItemData.Original_Qty) || 1,
        Notes: originalItemData.Item_Notes || "",
        Order_Item_Key: originalItemData.Order_Item_Key || ""
    });
}

const finalProfit = totalRevenue - totalBaseCost;

return [{
    json: {
        ...firstNodeData,              
        Total_Revenue: totalRevenue,   
        Total_Cost: totalBaseCost,     
        Final_Profit: finalProfit,     
        Deposit: deposit,              
        Balance: balance,              
        Additional_Fee: additionalFee, 
        Raw_Form_State: rawFormState,
        Sub_Items: packedItems         
    }
}];

// === V45.7.4 Parse Items & Generate SKU (SKU Normalization Layer) ===
const body = $("Receive Dashboard Order").first().json.body || $("Receive Dashboard Order").first().json;
const orderId = body.Order_ID || "未命名";
const customer = body.Customer_Name || "未命名";
const appDate = body.Appointment_Date || null;
const revenue = (body.Deposit || 0) + (body.Balance || 0) + (body.Additional_Fee || 0);
const rawText = body.Full_Order_Text || "";
const rawState = body.Raw_Form_State || "";

let outputItems = [];

// V45.7.4: Support both Order_Items_List (Dashboard) and Items (legacy/test)
const itemsList = body.Order_Items_List || body.Items;

if (itemsList && Array.isArray(itemsList)) {
    for (const item of itemsList) {
        let sku = item.Product_Name || "";
        const qty = Number(item.Quantity) || 1;

        // === 1. 3D Display SKU Normalization (Bible V3.7 Section 4) ===
        // Handles: 木框款式/木框套裝/立體擺設(木框) → 木框套裝 (N肢)
        // Rule: 3肢 maps to 4肢 pricing per V3.7
        if (sku.includes("木框")) {
            let limb = (sku.includes("4肢") || sku.includes("3肢")) ? "(4肢)" : "(2肢)";
            sku = `木框套裝 ${limb}`;
        } else if (sku.includes("玻璃瓶")) {
            let limb = (sku.includes("4肢") || sku.includes("3肢")) ? "(4肢)" : "(2肢)";
            sku = `玻璃瓶套裝 ${limb}`;
        }

        // === 2. Keychain SKU Normalization ===
        // Dashboard sends: "嬰兒鎖匙扣 - 不銹鋼" + Mode: "(加購)"
        // Airtable expects: "嬰兒鎖匙扣 - 不銹鋼 - {qty}飾 {mode}"
        if (sku.includes("鎖匙扣") && item.Mode) {
            sku = `${sku} - ${qty}飾 ${item.Mode}`;
        }

        // === 3. Jewelry/Charm SKU Normalization ===
        // Dashboard sends: "嬰兒吊飾 - 925銀" + Mode: "(加購)"
        // Airtable expects: "嬰兒吊飾 - 925銀 - {qty}飾 {mode}"
        if (sku.includes("吊飾") && item.Mode) {
            sku = `${sku} - ${qty}飾 ${item.Mode}`;
        }

        let shipping_saved = (sku.includes("鎖匙扣") && qty > 1) ? (qty - 1) * 20 : 0;
        let necklace_saved = (sku.includes("吊飾")) ? Math.floor(qty / 2) * 220 : 0;

        outputItems.push({
            json: {
                Order_ID: orderId,
                Customer_Name: customer,
                Appointment_Date: appDate,
                Total_Revenue: revenue,
                Order_Text: rawText,
                Raw_Form_State: rawState,
                Search_SKU: sku,
                Original_Qty: qty,
                Item_Notes: item.Notes || "",
                Order_Item_Key: item.Order_Item_Key || "",
                Shipping_Deduction: shipping_saved,
                Necklace_Deduction: necklace_saved
            }
        });
    }
} else {
    outputItems.push({ json: { Order_ID: orderId, Customer_Name: customer, Total_Revenue: revenue, Order_Text: rawText, Raw_Form_State: rawState, Search_SKU: "無商品", Shipping_Deduction: 0, Necklace_Deduction: 0 }});
}
return outputItems;

// Profit Auditor V45.8 - Anti-Loss Guard
// Business logic: Ling Au sets prices manually; system price is reference only.
// Audit purpose: only alert if actual collected < system cost (selling at a loss)
const body = $("Receive Dashboard Order").first().json.body || $("Receive Dashboard Order").first().json;

const deposit       = Number(body.Deposit)           || 0;
const balance       = Number(body.Balance)           || 0;
const additionalFee = Number(body.Additional_Fee)    || 0;
const actualTotal   = deposit + balance + additionalFee;
const systemCost    = Number(body.System_Total_Cost) || 0;

let auditResults = {
    auditPassed: true,
    systemCost:  systemCost,
    actualTotal: actualTotal,
    discrepancy: 0,
    reasons:     [],
    orderId:     body.Order_ID      || "Unknown",
    customer:    body.Customer_Name || "Unknown",
    role:        body.Role          || "ling"
};

// Only audit when both values are meaningful (skip if no payment entered yet)
if (actualTotal > 0 && systemCost > 0) {
    if (actualTotal < systemCost) {
        const diff = systemCost - actualTotal;
        auditResults.auditPassed = false;
        auditResults.discrepancy = diff;
        auditResults.reasons.push(`At-a-loss alert: collected $${actualTotal}, cost $${systemCost}, gap $${diff}`);
    }
}

return [{ json: auditResults }];

